# Contract Model\n\nclass Contract:\n    def __init__(self, contract_id, party_one, party_two, terms, start_date, end_date):\n        self.contract_id = contract_id  # Unique identifier for the contract\n        self.party_one = party_one  # Name of the first party involved\n        self.party_two = party_two  # Name of the second party involved\n        self.terms = terms  # Terms and conditions of the contract\n        self.start_date = start_date  # Start date of the contract\n        self.end_date = end_date  # End date of the contract\n\n    def is_active(self):\n        # Logic to determine if the contract is currently active\n        return self.start_date <= datetime.now() <= self.end_date\n\n    def __str__(self):\n        return f'Contract {self.contract_id} between {self.party_one} and {self.party_two}'\n